oxy_webhelp_navlinks = {"nas_smb_local_user_mgmt-d30753e43706":{"topics":[{"title":"Configuring SMB authentication for namespaces","shortdesc":"<p class=\"shortdesc\">For NetApp, Isilon, and Pure FlashBlade namespaces, configure SMB credentials at the         namespace level to enable SMB authentication for NAS shares.<\/p>","href":"nas\/nas_configuring_smb_auth_namespace.html","attributes":{"data-id":"nas_configuring_smb_auth_namespace"},"menu":{"hasChildren":false},"tocID":"nas_configuring_smb_auth_namespace-d30753e43717","topics":[]},{"title":"Configuring SMB authentication for SMB shares","shortdesc":"<p class=\"shortdesc\">For NetApp and Isilon systems, configure SMB credentials manually at the SMB share         level to enable SMB authentication and protection for SMB for all namespaces and shares on         the system.<\/p>","href":"nas\/nas_configuring_smb_auth_shares.html","attributes":{"data-id":"nas_configuring_smb_auth_shares"},"menu":{"hasChildren":false},"tocID":"nas_configuring_smb_auth_shares-d30753e43728","topics":[]},{"title":"Configuring SMB authentication for NAS systems","shortdesc":"<p class=\"shortdesc\">For NetApp and Isilon systems, configure SMB credentials manually at the system         level to enable SMB authentication for all namespaces and NAS shares on the system, or to         meet your site requirements for SMB authentication.<\/p>","href":"nas\/nas_configuring_smb_auth_system.html","attributes":{"data-id":"nas_configuring_smb_auth_system"},"menu":{"hasChildren":false},"tocID":"nas_configuring_smb_auth_system-d30753e43739","topics":[]}]}};